// ───────────────────────────────────────────────────────────────
// MODULE: Causal Edges
// ───────────────────────────────────────────────────────────────
// Feature catalog: Causal edge creation (memory_causal_link)
// Causal relationship graph for memory lineage
import type Database from 'better-sqlite3';
import { clearDegreeCacheForDb } from '../search/graph-search-fn.js';
import { clearGraphSignalsCache } from '../graph/graph-signals.js';
import { detectContradictions } from '../graph/contradiction-detection.js';
import { ensureTemporalColumns } from '../graph/temporal-edges.js';
import { isTemporalEdgesEnabled } from '../search/search-flags.js';
import { runInTransaction } from './transaction-manager.js';
import { sweepCausalEdges } from '../causal/sweep.js';
import type { CausalEdgeSweepResult } from '../causal/sweep.js';

/* ───────────────────────────────────────────────────────────────
   1. CONSTANTS
----------------------------------------------------------------*/

const RELATION_TYPES = Object.freeze({
  CAUSED: 'caused',
  ENABLED: 'enabled',
  SUPERSEDES: 'supersedes',
  CONTRADICTS: 'contradicts',
  DERIVED_FROM: 'derived_from',
  SUPPORTS: 'supports',
} as const);

type RelationType = typeof RELATION_TYPES[keyof typeof RELATION_TYPES];

/**
 * C138: Relation weight multipliers applied during traversal scoring.
 * Higher values amplify the propagated strength; values < 1.0 dampen it.
 */
const RELATION_WEIGHTS: Record<string, number> = {
  supersedes:   1.5,  // Strongest signal — new info replaces old
  caused:       1.3,  // Strong causal link
  enabled:      1.1,  // Weak causal link
  supports:     1.0,  // Neutral / default
  derived_from: 1.0,  // Neutral / default
  contradicts:  0.8,  // Dampened — conflicting signals lower confidence
};

const DEFAULT_MAX_DEPTH = 3;
const MAX_EDGES_LIMIT = 100;

// Edge bounds for the lightweight runtime path (NFR-R01, SC-005)
const MAX_EDGES_PER_NODE = 20;
const MAX_AUTO_STRENGTH = 0.5;
const MAX_STRENGTH_INCREASE_PER_CYCLE = 0.05;
const WINDOW_MS = parsePositiveIntegerEnv('SPECKIT_CAUSAL_RELATION_WINDOW_MS', 15 * 60 * 1000);
const CAP_PER_WINDOW = parsePositiveIntegerEnv('SPECKIT_CAUSAL_RELATION_CAP_PER_WINDOW', 100);
const STALENESS_THRESHOLD_DAYS = 90;
const DECAY_STRENGTH_AMOUNT = 0.1;
const DECAY_PERIOD_DAYS = 30;

function parsePositiveIntegerEnv(name: string, fallback: number): number {
  const value = process.env[name];
  if (!value) return fallback;
  const parsed = Number.parseInt(value, 10);
  return Number.isInteger(parsed) && parsed > 0 ? parsed : fallback;
}

function isFiniteNumber(value: unknown): value is number {
  return typeof value === 'number' && Number.isFinite(value);
}

/**
 * Classify edge provenance as automatic. Covers the legacy 'auto' creator and
 * namespaced automatic creators such as 'auto-session'. Shared by the insert
 * cap path and the consolidation strengthening cap so the two sites cannot
 * drift. Non-auto values ('manual', 'automatic', 'author') must not match.
 */
function isAutoEdgeCreator(createdBy: string | null | undefined): boolean {
  return createdBy === 'auto'
    || (typeof createdBy === 'string' && createdBy.startsWith('auto-'));
}

function clampStrength(strength: number): number | null {
  if (!Number.isFinite(strength)) return null;
  return Math.max(0, Math.min(1, strength));
}

function normalizeCausalEdgeRow(row: Record<string, unknown>): CausalEdge {
  return {
    id: Number(row.id),
    source_id: String(row.source_id),
    target_id: String(row.target_id),
    source_anchor: row.source_anchor == null ? null : String(row.source_anchor),
    target_anchor: row.target_anchor == null ? null : String(row.target_anchor),
    relation: String(row.relation) as RelationType,
    strength: Number(row.strength),
    evidence: row.evidence == null ? null : String(row.evidence),
    extracted_at: String(row.extracted_at),
    created_by: String(row.created_by ?? 'manual'),
    last_accessed: row.last_accessed == null ? null : String(row.last_accessed),
  };
}

/* ───────────────────────────────────────────────────────────────
   2. INTERFACES
----------------------------------------------------------------*/

interface CausalEdge {
  id: number;
  source_id: string;
  target_id: string;
  source_anchor: string | null;
  target_anchor: string | null;
  relation: RelationType;
  strength: number;
  evidence: string | null;
  extracted_at: string;
  created_by: string;
  last_accessed: string | null;
}

interface CausalEdgeRow extends Record<string, unknown> {
  id: number;
  source_id: string;
  target_id: string;
  source_anchor?: string | null;
  target_anchor?: string | null;
  relation: RelationType;
  strength: number;
  evidence: string | null;
  extracted_at: string;
  created_by: string;
  last_accessed: string | null;
}

type EdgeQueryResult = CausalEdge[] & {
  truncated: boolean;
  limit: number;
};

interface WeightHistoryEntry {
  id: number;
  edge_id: number;
  old_strength: number;
  new_strength: number;
  changed_by: string;
  changed_at: string;
  reason: string | null;
}

interface GraphStats {
  totalEdges: number;
  byRelation: Record<string, number>;
  avgStrength: number;
  uniqueSources: number;
  uniqueTargets: number;
}

interface DeleteEdgeOptions {
  reason?: string;
  command?: string;
  restoreContext?: Record<string, unknown>;
}

interface InsertEdgeMetadataOptions {
  confidence?: number;
  extractionMethod?: string;
}

interface InsertEdgeOutcome {
  status: 'inserted' | 'updated' | 'skipped';
  reason: string | null;
  edgeId: number | null;
}

interface CausalChainNode {
  id: string;
  edgeId?: number;          // Preserve causal_edges.id for unlink workflow
  depth: number;
  relation: RelationType;
  strength: number;
  children: CausalChainNode[];
  truncated?: boolean;
  truncationLimit?: number | null;
}

/* ───────────────────────────────────────────────────────────────
   3. MODULE STATE
----------------------------------------------------------------*/

let db: Database.Database | null = null;
let lastInsertEdgeOutcome: InsertEdgeOutcome | null = null;

/**
 * Monotonically-increasing generation counter bumped on every causal-edge
 * mutation (insert/update/delete/rollback). Read-only callers can include this
 * value in cache keys (e.g. memory_search when `enableCausalBoost=true`) so
 * cached responses derived from the causal graph become stale on the next
 * lookup without requiring a wholesale tool-cache invalidation.
 *
 * targeted memory_search cache invalidation.
 */
let causalEdgesGeneration = 0;

function bumpCausalEdgesGeneration(): void {
  // Wrap counter near MAX_SAFE_INTEGER to avoid overflow in ultra-long-lived
  // Processes; consumers only compare for inequality, so wrapping is safe.
  causalEdgesGeneration = causalEdgesGeneration >= Number.MAX_SAFE_INTEGER
    ? 1
    : causalEdgesGeneration + 1;
}

function getCausalEdgesGeneration(): number {
  return causalEdgesGeneration;
}

function setLastInsertEdgeOutcome(outcome: InsertEdgeOutcome): void {
  lastInsertEdgeOutcome = outcome;
}

function getLastInsertEdgeOutcome(): InsertEdgeOutcome | null {
  return lastInsertEdgeOutcome;
}

function invalidateDegreeCache(): void {
  // bump the causal-edges generation FIRST so any cache key that
  // includes it (e.g. memory_search when enableCausalBoost=true) becomes
  // stale on the next read without invalidating unrelated tool entries.
  bumpCausalEdgesGeneration();

  try {
    // H1 FIX: Use db-specific cache invalidation instead of the no-op global version
    if (db) {
      clearDegreeCacheForDb(db);
    }
  } catch (_error: unknown) {
    // Cache invalidation is best-effort; never block edge mutations
  }
  try {
    clearGraphSignalsCache();
  } catch (_error: unknown) {
    // Graph signals cache invalidation is best-effort
  }
}

function enforceRelationWindowCap(
  relation: string,
  database: Database.Database,
  windowMs: number = WINDOW_MS,
  capPerWindow: number = CAP_PER_WINDOW,
): boolean {
  try {
    const windowStart = new Date(Date.now() - windowMs).toISOString();
    const row = (database.prepare(`
      SELECT COUNT(*) as count FROM causal_edges
      WHERE relation = ?
        AND datetime(extracted_at) >= datetime(?)
    `) as Database.Statement).get(relation, windowStart) as { count: number };
    const count = row.count;
    if (count >= capPerWindow) {
      console.warn(`[causal-edges] cap exceeded for relation ${relation}: ${count}/${capPerWindow} in ${windowMs}ms window`);
      return false;
    }
    return true;
  } catch (error: unknown) {
    const msg = error instanceof Error ? error.message : String(error);
    console.warn(`[causal-edges] relation cap check failed for ${relation}: ${msg}`);
    return true;
  }
}

/* ───────────────────────────────────────────────────────────────
   4. INITIALIZATION
----------------------------------------------------------------*/

function init(database: Database.Database): void {
  db = database;

  // Defensive traversal indexes — the canonical creation lives in
  // Vector-index-impl.ts migration v8. These IF NOT EXISTS guards
  // Ensure the indexes are present even when the module is initialised outside
  // The normal migration path (e.g. tests, standalone scripts).
  try {
    database.exec('CREATE INDEX IF NOT EXISTS idx_causal_source ON causal_edges(source_id)');
    database.exec('CREATE INDEX IF NOT EXISTS idx_causal_target ON causal_edges(target_id)');
    ensureTemporalColumns(database);
  } catch (_e: unknown) {
    // Best-effort: table may not exist yet during early startup sequencing
  }
}

/* ───────────────────────────────────────────────────────────────
   5. EDGE OPERATIONS
----------------------------------------------------------------*/

function insertEdge(
  sourceId: string,
  targetId: string,
  relation: RelationType,
  strength: number = 1.0,
  evidence: string | null = null,
  shouldInvalidateCache: boolean = true,
  createdBy: string = 'manual',
  anchors: { sourceAnchor?: string | null; targetAnchor?: string | null } = {},
  metadata: InsertEdgeMetadataOptions = {},
): number | null {
  lastInsertEdgeOutcome = null;
  if (!db) {
    console.warn('[causal-edges] Database not initialized. Server may still be starting up.');
    setLastInsertEdgeOutcome({ status: 'skipped', reason: 'database not initialized', edgeId: null });
    return null;
  }
  const database = db;

  // NFR-R01: Auto edges capped at MAX_AUTO_STRENGTH
  const effectiveStrength = isAutoEdgeCreator(createdBy)
    ? Math.min(strength, MAX_AUTO_STRENGTH)
    : strength;

  // Prevent self-loops
  if (sourceId === targetId) {
    setLastInsertEdgeOutcome({ status: 'skipped', reason: 'self-loop', edgeId: null });
    return null;
  }

  // FK check deferred — test environments use synthetic IDs not in memory_index.
  // Implementing FK validation would require seeding memory_index in 20+ causal edge tests.

  // NFR-R01: Edge bounds — reject if node already has MAX_EDGES_PER_NODE auto edges
  if (isAutoEdgeCreator(createdBy)) {
    const edgeCount = countEdgesForNode(sourceId);
    if (edgeCount >= MAX_EDGES_PER_NODE) {
      console.warn(`[causal-edges] Edge bounds: node ${sourceId} has ${edgeCount} edges (max ${MAX_EDGES_PER_NODE}), rejecting auto edge`);
      setLastInsertEdgeOutcome({ status: 'skipped', reason: 'edge bounds exceeded', edgeId: null });
      return null;
    }
  }

  try {
    const clampedStrength = clampStrength(effectiveStrength);
    if (clampedStrength === null) {
      console.warn('[causal-edges] insertEdge rejected non-finite strength');
      setLastInsertEdgeOutcome({ status: 'skipped', reason: 'non-finite strength', edgeId: null });
      return null;
    }

    // Wrap SELECT + UPSERT + logWeightChange in a transaction for atomicity
    const rowId = database.transaction(() => {
      if (isTemporalEdgesEnabled()) {
        detectContradictions(
          database,
          Number.parseInt(sourceId, 10),
          Number.parseInt(targetId, 10),
          relation,
        );
      }

      // Check if edge exists (for weight_history logging on conflict update).
      // This SELECT is intentional: we need the old strength to decide whether
      // To write a weight_history row after the upsert. The subsequent INSERT
      // Uses last_insert_rowid() to avoid a second post-upsert SELECT.
      const existing = (database.prepare(`
        SELECT id, strength, evidence, created_by FROM causal_edges
        WHERE source_id = ? AND target_id = ? AND relation = ?
          AND COALESCE(source_anchor, '') = COALESCE(?, '')
          AND COALESCE(target_anchor, '') = COALESCE(?, '')
      `) as Database.Statement).get(
        sourceId,
        targetId,
        relation,
        anchors.sourceAnchor ?? null,
        anchors.targetAnchor ?? null,
      ) as { id: number; strength: number; evidence: string | null; created_by: string | null } | undefined;

      // Manual/curated edges must never be overwritten by automatic writers:
      // an auto upsert against a non-auto row is skipped so curated provenance
      // and strength survive. Auto-to-auto updates remain allowed under caps.
      if (existing && isAutoEdgeCreator(createdBy) && !isAutoEdgeCreator(existing.created_by ?? 'manual')) {
        console.warn(
          `[causal-edges] skipped manual edge ${existing.id} (created_by=${existing.created_by ?? 'manual'}); skipped overwrite by ${createdBy}`,
        );
        setLastInsertEdgeOutcome({ status: 'skipped', reason: 'skipped manual edge', edgeId: existing.id });
        return 0;
      }

      const columns = new Set((database.prepare('PRAGMA table_info(causal_edges)').all() as Array<{ name: string }>)
        .map((column) => column.name));

      if (existing) {
        const assignments = [
          'strength = ?',
          'evidence = COALESCE(?, evidence)',
          'created_by = ?',
        ];
        const params: unknown[] = [clampedStrength, evidence, createdBy];
        if (columns.has('confidence') && metadata.confidence !== undefined) {
          assignments.push('confidence = ?');
          params.push(metadata.confidence);
        }
        if (columns.has('extraction_method') && metadata.extractionMethod !== undefined) {
          assignments.push('extraction_method = ?');
          params.push(metadata.extractionMethod);
        }
        params.push(existing.id);

        (database.prepare(`
          UPDATE causal_edges
          SET ${assignments.join(',\n              ')}
          WHERE id = ?
        `) as Database.Statement).run(...params);
        setLastInsertEdgeOutcome({ status: 'updated', reason: null, edgeId: existing.id });
      } else {
        if (!enforceRelationWindowCap(relation, database)) {
          setLastInsertEdgeOutcome({ status: 'skipped', reason: 'relation cap exceeded', edgeId: null });
          return 0;
        }

        const insertColumns = [
          'source_id',
          'target_id',
          'source_anchor',
          'target_anchor',
          'relation',
          'strength',
          'evidence',
          'created_by',
        ];
        const insertValues: unknown[] = [
          sourceId,
          targetId,
          anchors.sourceAnchor ?? null,
          anchors.targetAnchor ?? null,
          relation,
          clampedStrength,
          evidence,
          createdBy,
        ];
        if (columns.has('confidence') && metadata.confidence !== undefined) {
          insertColumns.push('confidence');
          insertValues.push(metadata.confidence);
        }
        if (columns.has('extraction_method') && metadata.extractionMethod !== undefined) {
          insertColumns.push('extraction_method');
          insertValues.push(metadata.extractionMethod);
        }

        (database.prepare(`
          INSERT INTO causal_edges (
            ${insertColumns.join(',\n            ')}
          )
          VALUES (${insertColumns.map(() => '?').join(', ')})
        `) as Database.Statement).run(...insertValues);
      }

      const row = (database.prepare(`
        SELECT id FROM causal_edges
        WHERE source_id = ? AND target_id = ? AND relation = ?
          AND COALESCE(source_anchor, '') = COALESCE(?, '')
          AND COALESCE(target_anchor, '') = COALESCE(?, '')
      `) as Database.Statement).get(
        sourceId,
        targetId,
        relation,
        anchors.sourceAnchor ?? null,
        anchors.targetAnchor ?? null,
      ) as { id: number } | undefined;
      const rowId = row ? row.id : 0;
      if (!existing && rowId) {
        setLastInsertEdgeOutcome({ status: 'inserted', reason: null, edgeId: rowId });
      }

      // Log weight change on conflict update
      if (existing && rowId && isFiniteNumber(existing.strength) && existing.strength !== clampedStrength) {
        logWeightChange(rowId, existing.strength, clampedStrength, createdBy, 'insert-upsert');
      }

      return rowId;
    })();

    if (shouldInvalidateCache) {
      invalidateDegreeCache();
    }

    return rowId || null;
  } catch (error: unknown) {
    const msg = error instanceof Error ? error.message : String(error);
    console.warn(`[causal-edges] insertEdge error: ${msg}`);
    setLastInsertEdgeOutcome({ status: 'skipped', reason: msg, edgeId: null });
    if (/SQLITE_BUSY|SQLITE_LOCKED|database is locked/i.test(msg)) {
      throw error;
    }
    return null;
  }
}

function insertEdgesBatch(
  edges: Array<{
    sourceId: string;
    targetId: string;
    relation: RelationType;
    strength?: number;
    evidence?: string | null;
    createdBy?: string;
    sourceAnchor?: string | null;
    targetAnchor?: string | null;
    confidence?: number;
    extractionMethod?: string;
  }>
): { inserted: number; failed: number; skippedManual: number } {
  if (!db) return { inserted: 0, failed: edges.length, skippedManual: 0 };

  let inserted = 0;
  let failed = 0;
  let skippedManual = 0;

  const insertTx = db.transaction(() => {
    for (const edge of edges) {
      const id = insertEdge(
        edge.sourceId,
        edge.targetId,
        edge.relation,
        edge.strength ?? 1.0,
        edge.evidence ?? null,
        false,
        edge.createdBy ?? 'manual',
        {
          sourceAnchor: edge.sourceAnchor ?? null,
          targetAnchor: edge.targetAnchor ?? null,
        },
        {
          confidence: edge.confidence,
          extractionMethod: edge.extractionMethod,
        },
      );
      if (id !== null) inserted++;
      else {
        failed++;
        if (getLastInsertEdgeOutcome()?.reason === 'skipped manual edge') {
          skippedManual++;
        }
      }
    }
  });

  try {
    insertTx();
    if (inserted > 0) {
      invalidateDegreeCache();
    }
  } catch (error: unknown) {
    const msg = error instanceof Error ? error.message : String(error);
    console.warn(`[causal-edges] insertEdgesBatch error: ${msg}`);
  }

  return { inserted, failed, skippedManual };
}

function bulkInsertEdges(edges: Array<Record<string, unknown>>): { inserted: number; failed: number } {
  if (!db) return { inserted: 0, failed: edges.length };

  const database = db;
  let inserted = 0;
  let failed = 0;

  try {
    const edgeColumns = (database.prepare('PRAGMA table_info(causal_edges)').all() as Array<{ name: string }>)
      .map((column) => column.name)
      .filter((name) => typeof name === 'string' && name.length > 0 && name !== 'id');

    if (edgeColumns.length === 0) {
      return { inserted: 0, failed: edges.length };
    }

    const insertEdgeStmt = database.prepare(`
      INSERT OR IGNORE INTO causal_edges (${edgeColumns.join(', ')})
      VALUES (${edgeColumns.map(() => '?').join(', ')})
    `) as Database.Statement;

    const insertTx = database.transaction(() => {
      for (const edge of edges) {
        if (!edge || typeof edge.source_id !== 'string' || typeof edge.target_id !== 'string') {
          failed++;
          continue;
        }
        if (typeof edge.relation !== 'string' || edge.relation.trim().length === 0) {
          failed++;
          continue;
        }
        if (edge.source_id === edge.target_id) {
          failed++;
          continue;
        }
        if (!enforceRelationWindowCap(edge.relation, database)) {
          failed++;
          continue;
        }

        const result = insertEdgeStmt.run(...edgeColumns.map((column) => edge[column] ?? null)) as { changes: number };
        if (result.changes > 0) {
          inserted++;
        }
      }
    });

    insertTx();
    if (inserted > 0) {
      invalidateDegreeCache();
    }
  } catch (error: unknown) {
    const msg = error instanceof Error ? error.message : String(error);
    console.warn(`[causal-edges] bulkInsertEdges error: ${msg}`);
  }

  return { inserted, failed };
}

function createEdgeQueryResult(
  edges: CausalEdge[],
  limit: number,
  truncated: boolean,
): EdgeQueryResult {
  const result = edges as EdgeQueryResult;
  result.truncated = truncated;
  result.limit = limit;
  return result;
}

function getEdgesFrom(sourceId: string, limit: number = MAX_EDGES_LIMIT): EdgeQueryResult {
  if (!db) return createEdgeQueryResult([], limit, false);

  try {
    const rows = (db.prepare(`
      SELECT * FROM causal_edges
      WHERE source_id = ?
      ORDER BY strength DESC
      LIMIT ?
    `) as Database.Statement).all(sourceId, limit + 1) as CausalEdgeRow[];
    const truncated = rows.length > limit;
    const edges = (truncated ? rows.slice(0, limit) : rows).map(normalizeCausalEdgeRow);
    for (const edge of edges) {
      try { touchEdgeAccess(edge.id); } catch (e: unknown) {
        console.warn(`[causal-edges] touchEdgeAccess failed for edge ${edge.id}: ${e instanceof Error ? e.message : String(e)}`);
      }
    }
    return createEdgeQueryResult(edges, limit, truncated);
  } catch (error: unknown) {
    const msg = error instanceof Error ? error.message : String(error);
    console.warn(`[causal-edges] getEdgesFrom error: ${msg}`);
    return createEdgeQueryResult([], limit, false);
  }
}

function getEdgesTo(targetId: string, limit: number = MAX_EDGES_LIMIT): EdgeQueryResult {
